/**
 * Theme definitions for T3 Code.
 *
 * Pure data module — no React, no DOM, no side-effects.
 * Consumed by the web app's `useTheme` hook to apply CSS custom properties.
 */

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface ThemeColors {
  readonly background: string;
  readonly foreground: string;
  readonly accent: string;
  readonly sidebar: string;
  readonly editor: string;
  readonly terminal: string;
  readonly statusBar: string;
}

export interface ThemeDefinition {
  readonly id: string;
  readonly name: string;
  readonly colors: ThemeColors;
  readonly fontFamily: string;
  readonly fontSize: number;
  /**
   * Drives the `.dark` CSS class and the `resolvedTheme` value consumed by
   * diff-rendering, syntax-highlighting and other appearance-aware components.
   */
  readonly appearance: "light" | "dark";
}

// ---------------------------------------------------------------------------
// Built-in themes
// ---------------------------------------------------------------------------

const t3Dark: ThemeDefinition = {
  id: "t3-dark",
  name: "Dark",
  appearance: "dark",
  colors: {
    background: "#0c0c0d",
    foreground: "#e5e5e5",
    accent: "#7c6fe0",
    sidebar: "#111113",
    editor: "#0c0c0d",
    terminal: "#09090b",
    statusBar: "#141416",
  },
  fontFamily:
    '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
  fontSize: 14,
};

const t3Light: ThemeDefinition = {
  id: "t3-light",
  name: "Light",
  appearance: "light",
  colors: {
    background: "#ffffff",
    foreground: "#262626",
    accent: "#6239e0",
    sidebar: "#f5f5f5",
    editor: "#ffffff",
    terminal: "#ffffff",
    statusBar: "#f0f0f0",
  },
  fontFamily:
    '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
  fontSize: 14,
};

const t3Midnight: ThemeDefinition = {
  id: "t3-midnight",
  name: "Midnight",
  appearance: "dark",
  colors: {
    background: "#0b0e1a",
    foreground: "#c9d1e3",
    accent: "#5b9cf5",
    sidebar: "#080b14",
    editor: "#0b0e1a",
    terminal: "#060810",
    statusBar: "#0f1322",
  },
  fontFamily:
    '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
  fontSize: 14,
};

// ---------------------------------------------------------------------------
// Registry
// ---------------------------------------------------------------------------

const BUILT_IN_THEMES: readonly ThemeDefinition[] = [
  t3Dark,
  t3Light,
  t3Midnight,
];

const THEME_MAP = new Map<string, ThemeDefinition>(
  BUILT_IN_THEMES.map((t) => [t.id, t]),
);

export const DEFAULT_THEME_ID = "t3-dark" as const;

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/** Return a theme by `id`, or `undefined` when the id is unknown. */
export function getTheme(id: string): ThemeDefinition | undefined {
  return THEME_MAP.get(id);
}

/** Return every registered built-in theme. */
export function listThemes(): readonly ThemeDefinition[] {
  return BUILT_IN_THEMES;
}

