import { useCallback, useSyncExternalStore } from "react";
import {
  DEFAULT_THEME_ID,
  getTheme,
  listThemes,
  type ThemeDefinition,
} from "@t3tools/shared/themes";

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const STORAGE_KEY = "t3code:theme:v2";
const LEGACY_STORAGE_KEY = "t3code:theme";

/**
 * CSS custom properties written to `document.documentElement.style` whenever
 * the active theme changes.  Keys are CSS variable names (without the `--`
 * prefix); values are callbacks that pull the concrete value from a theme.
 */
const CSS_VAR_MAP: Record<string, (t: ThemeDefinition) => string> = {
  background: (t) => t.colors.background,
  foreground: (t) => t.colors.foreground,
  accent: (t) => t.colors.accent,
  "accent-foreground": (t) => t.colors.foreground,
  primary: (t) => t.colors.accent,
  ring: (t) => t.colors.accent,
  sidebar: (t) => t.colors.sidebar,
  editor: (t) => t.colors.editor,
  terminal: (t) => t.colors.terminal,
  "status-bar": (t) => t.colors.statusBar,
  "font-family": (t) => t.fontFamily,
  "font-size": (t) => `${String(t.fontSize)}px`,
};

// ---------------------------------------------------------------------------
// Module-level state (external store for useSyncExternalStore)
// ---------------------------------------------------------------------------

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeDefinition | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

// ---------------------------------------------------------------------------
// Storage helpers
// ---------------------------------------------------------------------------

/** Migrate the legacy `"t3code:theme"` key (light/dark/system) to a theme id. */
function migrateLegacyKey(): string | null {
  const legacy = localStorage.getItem(LEGACY_STORAGE_KEY);
  if (legacy === null) return null;

  let id: string;
  if (legacy === "light") {
    id = "t3-light";
  } else if (legacy === "dark") {
    id = "t3-dark";
  } else {
    // "system" or unknown — pick based on OS preference
    id = window.matchMedia("(prefers-color-scheme: dark)").matches
      ? "t3-dark"
      : "t3-light";
  }

  localStorage.setItem(STORAGE_KEY, id);
  localStorage.removeItem(LEGACY_STORAGE_KEY);
  return id;
}

function getStoredThemeId(): string {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw && getTheme(raw)) return raw;

  const migrated = migrateLegacyKey();
  if (migrated) return migrated;

  return DEFAULT_THEME_ID;
}

// ---------------------------------------------------------------------------
// DOM application
// ---------------------------------------------------------------------------

function applyTheme(theme: ThemeDefinition, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  // Toggle .dark class for Tailwind's dark variant
  document.documentElement.classList.toggle("dark", theme.appearance === "dark");

  // Apply CSS custom properties
  const style = document.documentElement.style;
  for (const [varName, getter] of Object.entries(CSS_VAR_MAP)) {
    style.setProperty(`--${varName}`, getter(theme));
  }

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyTheme(getTheme(getStoredThemeId()) ?? getTheme(DEFAULT_THEME_ID)!);

// ---------------------------------------------------------------------------
// Snapshot (useSyncExternalStore)
// ---------------------------------------------------------------------------

function getSnapshot(): ThemeDefinition {
  const id = getStoredThemeId();

  if (lastSnapshot && lastSnapshot.id === id) {
    return lastSnapshot;
  }

  lastSnapshot = getTheme(id) ?? getTheme(DEFAULT_THEME_ID)!;
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY || e.key === LEGACY_STORAGE_KEY) {
      const theme = getTheme(getStoredThemeId()) ?? getTheme(DEFAULT_THEME_ID)!;
      applyTheme(theme, true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useTheme() {
  const theme = useSyncExternalStore(subscribe, getSnapshot);

  const resolvedTheme: "light" | "dark" = theme.appearance;

  const setTheme = useCallback((id: string) => {
    const next = getTheme(id);
    if (!next) return;
    localStorage.setItem(STORAGE_KEY, id);
    applyTheme(next, true);
    emitChange();
  }, []);

  const availableThemes = listThemes();

  return { theme, setTheme, resolvedTheme, availableThemes } as const;
}

